import requests

BASE_URL = "http://localhost:8000"
LOGIN_URL = f"{BASE_URL}/api/auth/login"
PURCHASE_ORDERS_URL = f"{BASE_URL}/api/purchases/orders"
TIMEOUT = 30

def login():
    data = {
        "username": "zzzz",
        "password": "As123321",
        "company_code": "ae4e964a"
    }
    headers = {"Content-Type": "application/x-www-form-urlencoded"}
    response = requests.post(LOGIN_URL, data=data, headers=headers, timeout=TIMEOUT)
    response.raise_for_status()
    json_resp = response.json()
    assert "access_token" in json_resp, "Login response missing access_token"
    return json_resp["access_token"]


def test_create_purchase_order():
    token = login()
    headers = {
        "Authorization": f"Bearer {token}",
        "Content-Type": "application/json"
    }

    # Hardcode supplier_id and product_id since no supplier endpoints are defined in PRD
    supplier_id = 1

    purchase_order_payload = {
        "supplier_id": supplier_id,
        "lines": [
            {
                "product_id": 1,
                "qty": 10,
                "price": 100.0
            },
            {
                "product_id": 1,
                "qty": 5,
                "price": 200.0
            }
        ]
    }

    purchase_order_id = None
    try:
        response = requests.post(PURCHASE_ORDERS_URL, json=purchase_order_payload, headers=headers, timeout=TIMEOUT)
        assert response.status_code == 201, f"Expected 201 Created, got {response.status_code}"
        resp_json = response.json()
        assert "id" in resp_json, "Response missing purchase order id"
        purchase_order_id = resp_json["id"]

    finally:
        if purchase_order_id is not None:
            delete_url = f"{PURCHASE_ORDERS_URL}/{purchase_order_id}"
            del_resp = requests.delete(delete_url, headers=headers, timeout=TIMEOUT)


test_create_purchase_order()
